// ===== VERSION 7.4 LESSON AUDIO AND INSTRUCTOR NARRATIVE =====
let lessonSpeechState={utterance:null,topicIndex:null,paused:false};
function speechSupported(){return 'speechSynthesis' in window&&'SpeechSynthesisUtterance' in window}
function buildInstructorNarrative(t){return `Let's work through ${String(t.title||'this topic').replace(/^\d+\.\s*/,'')}. Picture this: ${t.example||''} Here is the rule I want you to understand: ${t.body||t.content||''} The mistake I commonly see from new drivers is this: ${t.mistake||''} Remember, recognize the situation early and make the safe decision before it becomes an emergency.`}
function lessonTakeaway(t){const body=(t.body||t.content||'').trim(),match=body.match(/^[^.!?]+[.!?]/);return match?match[0]:body}
function preferredSpeechRate(){const value=Number(localStorage.getItem('roadreadySpeechRate')||1);return [0.75,1,1.25,1.5].includes(value)?value:1}
function setSpeechStatus(text){const el=document.querySelector('#speechStatus');if(el)el.textContent=text}
function clearSpeakingHighlight(){document.querySelectorAll('.topic-block.speaking').forEach(el=>el.classList.remove('speaking'))}
function stopLessonSpeech(){if(speechSupported())speechSynthesis.cancel();clearSpeakingHighlight();lessonSpeechState={utterance:null,topicIndex:null,paused:false};setSpeechStatus('Audio stopped')}
function pauseLessonSpeech(){if(!speechSupported()||!speechSynthesis.speaking)return;speechSynthesis.pause();lessonSpeechState.paused=true;setSpeechStatus('Audio paused')}
function resumeLessonSpeech(){if(!speechSupported()||!speechSynthesis.paused)return;speechSynthesis.resume();lessonSpeechState.paused=false;setSpeechStatus('Reading lesson')}
function speakLessonText(text,topicIndex=null,label='Reading lesson'){
 if(!speechSupported()){alert('Text-to-speech is not supported by this browser.');return}
 speechSynthesis.cancel();clearSpeakingHighlight();
 const u=new SpeechSynthesisUtterance(text.replace(/\s+/g,' ').trim());u.rate=preferredSpeechRate();u.pitch=1;u.volume=1;
 const voices=speechSynthesis.getVoices(),voice=voices.find(v=>v.lang?.startsWith('en-US')&&/Samantha|Google US English|Microsoft.*Online|Natural/i.test(v.name))||voices.find(v=>v.lang?.startsWith('en-US'))||voices.find(v=>v.lang?.startsWith('en'));if(voice)u.voice=voice;
 if(topicIndex!==null){const el=document.querySelector(`[data-speech-topic="${topicIndex}"]`);if(el){el.classList.add('speaking');el.scrollIntoView({behavior:'smooth',block:'center'})}}
 u.onstart=()=>setSpeechStatus(label);u.onpause=()=>setSpeechStatus('Audio paused');u.onresume=()=>setSpeechStatus(label);
 u.onend=()=>{clearSpeakingHighlight();lessonSpeechState.utterance=null;setSpeechStatus('Audio complete')};
 u.onerror=e=>{clearSpeakingHighlight();lessonSpeechState.utterance=null;if(e.error!=='canceled')setSpeechStatus('Audio unavailable')};
 lessonSpeechState.utterance=u;lessonSpeechState.topicIndex=topicIndex;speechSynthesis.speak(u);
}
function topicSpeechText(t){return `${String(t.title||'').replace(/^\d+\.\s*/,'')}. ${t.instructorNarrative||buildInstructorNarrative(t)} Remember this: ${lessonTakeaway(t)}`}
function checkSpeechText(t){return `Quick check. ${t.check.q}. Choices. ${t.check.choices.map((c,i)=>`${String.fromCharCode(65+i)}. ${c}`).join('. ')}`}
function fullLessonSpeechText(l){return `${l.title}. Learning objective. ${l.objective}. ${l.intro}. `+l.topics.map((t,i)=>`Topic ${i+1}. ${topicSpeechText(t)}`).join(' ')+` Lesson summary. ${(l.summary||[]).join('. ')}`}
function setupLessonAudio(view,lesson){
 const controls=view.querySelector('.lesson-audio-toolbar');
 if(!speechSupported()){if(controls)controls.innerHTML='<span>Audio narration is unavailable in this browser.</span>';view.querySelectorAll('.audio-controls,.read-check').forEach(el=>el.hidden=true);return}
 const rate=view.querySelector('#speechRate');if(rate){rate.value=String(preferredSpeechRate());rate.onchange=()=>{localStorage.setItem('roadreadySpeechRate',rate.value);stopLessonSpeech();setSpeechStatus(`Speed set to ${rate.value}×`)}}
 view.querySelector('#readFullLesson').onclick=e=>{e.preventDefault();e.stopPropagation();speakLessonText(fullLessonSpeechText(lesson),null,'Reading full lesson')};
 view.querySelector('#pauseLesson').onclick=e=>{e.preventDefault();e.stopPropagation();pauseLessonSpeech()};
 view.querySelector('#resumeLesson').onclick=e=>{e.preventDefault();e.stopPropagation();resumeLessonSpeech()};
 view.querySelector('#stopLesson').onclick=e=>{e.preventDefault();e.stopPropagation();stopLessonSpeech()};
 view.querySelectorAll('.topic-read').forEach(btn=>btn.onclick=e=>{e.preventDefault();e.stopPropagation();const i=Number(btn.dataset.topic);speakLessonText(topicSpeechText(lesson.topics[i]),i,`Reading topic ${i+1}`)});
 view.querySelectorAll('.topic-pause').forEach(btn=>btn.onclick=e=>{e.preventDefault();e.stopPropagation();pauseLessonSpeech()});
 view.querySelectorAll('.topic-stop').forEach(btn=>btn.onclick=e=>{e.preventDefault();e.stopPropagation();stopLessonSpeech()});
 view.querySelectorAll('.read-check').forEach(btn=>btn.onclick=e=>{e.preventDefault();e.stopPropagation();const i=Number(btn.dataset.topic);speakLessonText(checkSpeechText(lesson.topics[i]),i,`Reading quick check ${i+1}`)});
}
window.addEventListener('beforeunload',stopLessonSpeech);
// ===== END VERSION 7.4 =====

function openLesson(s){stopLessonSpeech();const l=DATA.lessons[s],v=document.querySelector('#lessonViewer');
 if(!l||!Array.isArray(l.topics)){v.innerHTML='<div class="feedback"><h3>Lesson data unavailable</h3><p>Please upload the complete release and refresh.</p></div>';v.hidden=false;return}
 l.intro=l.intro||l.scenario||'';
 l.summary=Array.isArray(l.summary)?l.summary:(l.points||[]);
 l.topics=l.topics.map(t=>({...t,page:t.page||parseInt(l.manualPages)||1,body:t.body||t.content||'',check:{...(t.check||{}),feedback:t.check?.feedback||t.check?.explain||''}}));if(!currentProfile.lessonsViewed.includes(s)){currentProfile.lessonsViewed.push(s);save()}document.querySelector('#lessonListCard').hidden=true;v.hidden=false;let checks=l.topics.map((t,i)=>`<article class="topic-block" data-speech-topic="${i}"><div class="topic-number">${i+1}</div><div class="topic-content"><span class="eyebrow">TOPIC ${i+1} • MANUAL PAGE ${t.page}</span><h3>${t.title}</h3><div class="audio-controls"><button type="button" class="topic-read" data-topic="${i}">▶ Read Topic</button><button type="button" class="topic-pause secondary" data-topic="${i}">Pause</button><button type="button" class="topic-stop secondary" data-topic="${i}">Stop</button></div><div class="instructor-box"><b>Instructor narrative</b><p>${t.instructorNarrative||buildInstructorNarrative(t)}</p></div><div class="lesson-rule"><b>Key rule</b><p>${t.body}</p></div><div class="example-box"><b>Real-world example</b><p>${t.example}</p></div><div class="mistake-box"><b>What new drivers often get wrong</b><p>${t.mistake}</p></div><div class="remember-box"><b>Remember this</b><p>${lessonTakeaway(t)}</p></div><div class="mini-check" data-topic="${i}"><b>Quick check</b><button type="button" class="read-check secondary" data-topic="${i}">🔊 Read Question</button><p>${t.check.q}</p><div class="mini-choices">${t.check.choices.map((c,j)=>`<button data-answer="${j}">${String.fromCharCode(65+j)}. ${c}</button>`).join('')}</div><div class="mini-feedback"></div></div></div></article>`).join('');v.innerHTML=`<div class="card lesson-view"><span class="eyebrow">${s} • MANUAL PAGES ${l.manualPages}</span><h2>${l.title}</h2><div class="lesson-objective"><b>Learning objective:</b> ${l.objective}</div><p class="lesson-intro">${l.intro}</p><div class="lesson-audio-toolbar"><button id="readFullLesson">▶ Read Full Lesson</button><button id="pauseLesson" class="secondary">Pause</button><button id="resumeLesson" class="secondary">Resume</button><button id="stopLesson" class="secondary">Stop</button><label>Speed <select id="speechRate"><option value="0.75">0.75×</option><option value="1">1×</option><option value="1.25">1.25×</option><option value="1.5">1.5×</option></select></label><span id="speechStatus" role="status">Audio ready</span></div><div class="lesson-toc"><b>In this lesson</b>${l.topics.map((t,i)=>`<a href="#topic-${i}">${i+1}. ${t.title}</a>`).join('')}</div>${checks}<div class="lesson-summary"><h3>Lesson summary</h3><ul class="lesson-points">${l.summary.map(x=>`<li>${x}</li>`).join('')}</ul></div><div class="lesson-actions"><button id="lessonComplete">Mark lesson complete</button><button class="secondary" id="lessonQuiz">Take 15-Question Section Quiz</button><button class="secondary" id="lessonMastery">Take 25-Question Mastery Exam</button><button class="secondary" id="lessonManual">Open manual</button><button class="secondary" id="lessonBack">Back to lessons</button></div></div>`;v.querySelectorAll('.topic-block').forEach((el,i)=>el.id='topic-'+i);setupLessonAudio(v,l);v.querySelectorAll('.mini-check').forEach((box,i)=>{
 box.querySelectorAll('.mini-choices button[data-answer]').forEach(btn=>btn.onclick=e=>{
  e.preventDefault();e.stopPropagation();
  if(box.dataset.done)return;
  box.dataset.done='1';
  const chosen=Number(btn.dataset.answer),correct=l.topics[i].check.answer;
  box.querySelectorAll('.mini-choices button[data-answer]').forEach(b=>{
   b.disabled=true;
   if(Number(b.dataset.answer)===correct)b.classList.add('correct');
   if(b===btn&&chosen!==correct)b.classList.add('wrong')
  });
  box.querySelector('.mini-feedback').innerHTML=`<div class="feedback ${chosen===correct?'good':''}"><b>${chosen===correct?'Correct':'Correct answer: '+l.topics[i].check.choices[correct]}</b><p>${l.topics[i].check.feedback}</p></div>`
 })
});v.querySelector('#lessonComplete').onclick=()=>{if(!currentProfile.lessonsCompleted.includes(s))currentProfile.lessonsCompleted.push(s);save();renderLessons();v.querySelector('#lessonComplete').textContent='Lesson completed ✓';v.querySelector('#lessonComplete').disabled=true};v.querySelector('#lessonQuiz').onclick=()=>{stopLessonSpeech();if(!currentProfile.lessonsCompleted.includes(s))currentProfile.lessonsCompleted.push(s);save();document.querySelector('#lessonListCard').hidden=false;v.hidden=true;startSection(s);switchTab('test')};
 v.querySelector('#lessonMastery').onclick=()=>{stopLessonSpeech();if(!currentProfile.lessonsCompleted.includes(s))currentProfile.lessonsCompleted.push(s);save();document.querySelector('#lessonListCard').hidden=false;v.hidden=true;startSectionMasteryExam(s);switchTab('test')};
 v.querySelector('#lessonManual').onclick=()=>openManual(parseInt(l.manualPages)||1);v.querySelector('#lessonBack').onclick=()=>{stopLessonSpeech();v.hidden=true;document.querySelector('#lessonListCard').hidden=false;renderLessons()};renderBadges();window.scrollTo({top:0,behavior:'smooth'})}
function renderAll(){
 const jobs=[['lessons',renderLessons],['metrics',renderMetrics],['sections',renderSections],['history',renderHistory],['goal',renderGoalAndReadiness],['badges',renderBadges],['examStatus',renderExamStatus],['learningInsights',renderLearningInsights],['learningCoach',renderLearningCoach],['readinessCenter',renderReadinessCenter]];
 jobs.forEach(([name,fn])=>{try{fn()}catch(err){console.error('Render failure:',name,err);if(name==='lessons'){const w=document.querySelector('#lessonCards');if(w)w.innerHTML='<div class="feedback"><h3>Lesson rendering error</h3><p>'+String(err.message||err)+'</p></div>';}}});
}

function switchTab(id){
 document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===id));
 document.querySelectorAll('.tab-panel').forEach(p=>p.classList.toggle('active',p.id===id))
}
document.querySelectorAll('.tabs button').forEach(b=>b.onclick=()=>switchTab(b.dataset.tab));
document.querySelector('#switchProfile').onclick=showProfiles;document.querySelector('#goalSettings').onclick=()=>{const n=Number(prompt('Daily study goal in minutes:',currentProfile.dailyGoal||15));if(Number.isFinite(n)&&n>=5&&n<=120){currentProfile.dailyGoal=Math.round(n);save();renderGoalAndReadiness()}};
document.querySelector('#addProfileBtn').onclick=()=>{
 const name=prompt('Student name:')?.trim();if(!name)return;
 if(state.profiles[name])return alert('That profile already exists.');
 state.profiles[name]=blankProfile(name);save();showProfiles()
};

function shuffled(a){return [...a].sort(()=>Math.random()-.5)}
function buildSectionQuiz(section,count=15){
 const pool=DATA.questions.filter(q=>q.section===section);
 if(pool.length<=count)return shuffled(pool);

 const byTopic={};
 pool.forEach(q=>{
   const topic=q.topic||q.learningObjective||'General';
   (byTopic[topic]||(byTopic[topic]=[])).push(q);
 });

 const selected=[],used=new Set();
 const topics=Object.keys(byTopic);

 // First pass: broad topic coverage.
 shuffled(topics).forEach(topic=>{
   if(selected.length>=count)return;
   const candidates=byTopic[topic].filter(q=>!used.has(q.id));
   if(!candidates.length)return;
   const ranked=candidates.sort((a,b)=>{
     const sa=currentProfile.questionStats?.[a.id]||{},sb=currentProfile.questionStats?.[b.id]||{};
     const wa=(sa.attempts||0)?1-(sa.correct||0)/(sa.attempts||1):1.15;
     const wb=(sb.attempts||0)?1-(sb.correct||0)/(sb.attempts||1):1.15;
     return wb-wa||(b.difficulty||2)-(a.difficulty||2);
   });
   selected.push(ranked[0]);used.add(ranked[0].id);
 });

 // Second pass: prioritize unseen, missed, weak, and harder questions.
 const remaining=pool.filter(q=>!used.has(q.id)).sort((a,b)=>{
   const sa=currentProfile.questionStats?.[a.id]||{},sb=currentProfile.questionStats?.[b.id]||{};
   const missedA=currentProfile.missed.includes(a.id)?2:0,missedB=currentProfile.missed.includes(b.id)?2:0;
   const unseenA=(sa.attempts||0)===0?3:0,unseenB=(sb.attempts||0)===0?3:0;
   const weakA=(sa.attempts||0)?1-(sa.correct||0)/(sa.attempts||1):1;
   const weakB=(sb.attempts||0)?1-(sb.correct||0)/(sb.attempts||1):1;
   const valueA=unseenA+missedA+weakA+(a.difficulty||2)*.2;
   const valueB=unseenB+missedB+weakB+(b.difficulty||2)*.2;
   return valueB-valueA;
 });
 for(const q of remaining){
   if(selected.length>=count)break;
   selected.push(q);used.add(q.id);
 }
 return shuffled(selected).slice(0,count);
}
function startSection(section){
 const qs=buildSectionQuiz(section,15);
 beginQuiz(qs,`${section} — 15-Question Section Quiz`,section);switchTab('test')
}
document.querySelectorAll('[data-count]').forEach(b=>b.onclick=()=>{
 const count=Number(b.dataset.count);beginQuiz(shuffled(DATA.questions).slice(0,count),`${count}-Question Practice Test`,null)
});
document.querySelector('#missedBtn').onclick=()=>{
 const ids=[...new Set(currentProfile.missed)];
 if(!ids.length)return alert('There are no missed questions to review.');
 beginQuiz(shuffled(DATA.questions.filter(q=>ids.includes(q.id))),`Missed Question Review`,null,true)
};

function beginQuiz(questions,type,section=null,review=false){
 quiz={questions,index:0,correct:0,type,section,review,answers:[],started:Date.now()};
 document.querySelector('#testSetup').hidden=true;document.querySelector('#quizArea').hidden=false;renderQuestion()
}
function renderQuestion(){
 const area=document.querySelector('#quizArea'),baseQ=quiz.questions[quiz.index];
 quiz.questionStarted=Date.now();
 const q={...baseQ};
 if(!quiz.answers[quiz.index]){
   const mapped=baseQ.choices.map((text,i)=>({text,isCorrect:i===baseQ.answer}));
   for(let i=mapped.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[mapped[i],mapped[j]]=[mapped[j],mapped[i]]}
   q.choices=mapped.map(x=>x.text);q.answer=mapped.findIndex(x=>x.isCorrect);
   quiz.displayQuestion=q;
 }else{Object.assign(q,quiz.displayQuestion||baseQ)}
 area.innerHTML=`<div class="card question-card">
 <div class="quiz-head"><span>${quiz.type}</span><b>${quiz.index+1} / ${quiz.questions.length}</b></div>
 <span class="eyebrow">${q.section} • MANUAL PAGE ${q.page}</span>
 <h2>${q.q}</h2><div class="choice-list">${q.choices.map((c,i)=>`<button class="choice" data-i="${i}">${String.fromCharCode(65+i)}. ${c}</button>`).join('')}</div>
 <div id="feedback"></div><div class="quiz-actions"><button class="secondary" id="quitQuiz">Exit test</button><button id="submitAnswer" disabled>Check answer</button></div></div>`;
 let selected=null;
 area.querySelectorAll('.choice').forEach(b=>b.onclick=()=>{if(area.dataset.locked)return;selected=Number(b.dataset.i);area.querySelectorAll('.choice').forEach(x=>x.classList.remove('selected'));b.classList.add('selected');area.querySelector('#submitAnswer').disabled=false});
 area.querySelector('#quitQuiz').onclick=()=>finishQuiz(true);
 area.querySelector('#submitAnswer').onclick=()=>{
  if(selected===null)return;area.dataset.locked='1';
  const correct=selected===q.answer;if(correct){quiz.correct++;currentProfile.correct++}else if(!currentProfile.missed.includes(q.id))currentProfile.missed.push(q.id);
  if(correct&&quiz.review)currentProfile.missed=currentProfile.missed.filter(id=>id!==q.id);
  currentProfile.answered++;
  const st=currentProfile.sectionStats[q.section]||{answered:0,correct:0,attempts:0,best:0};st.answered++;if(correct)st.correct++;currentProfile.sectionStats[q.section]=st;
  area.querySelectorAll('.choice').forEach(b=>{const i=Number(b.dataset.i);if(i===q.answer)b.classList.add('correct');if(i===selected&&!correct)b.classList.add('wrong');b.disabled=true});
  area.querySelector('#feedback').innerHTML=`<div class="feedback ${correct?'good':''}"><h3>${correct?'Correct':'Not quite'}</h3>${!correct?`<p><b>Correct answer:</b> ${q.choices[q.answer]}</p>`:''}<p>${q.explain}</p><p><a href="#" id="manualRef">View manual page ${q.page}</a></p></div>`;
  area.querySelector('#manualRef').onclick=e=>{e.preventDefault();openManual(q.page)};
  const responseSeconds=Math.max(1,Math.round((Date.now()-(quiz.questionStarted||Date.now()))/1000));
  recordQuestionPerformance(q,correct,responseSeconds,quiz.review?'review':'practice');
  quiz.answers.push({id:q.id,selected,correct,responseSeconds});save();
  const submit=area.querySelector('#submitAnswer');submit.disabled=false;submit.textContent=quiz.index===quiz.questions.length-1?'See results':'Next question';submit.onclick=()=>{delete area.dataset.locked;if(++quiz.index>=quiz.questions.length)finishQuiz(false);else renderQuestion()}
 }
}
function finishQuiz(abandoned){
 const area=document.querySelector('#quizArea');
 if(abandoned){area.hidden=true;document.querySelector('#testSetup').hidden=false;quiz=null;return}
 const score=Math.round(quiz.correct/quiz.questions.length*100),passed=score>=80;
 currentProfile.tests.push({date:Date.now(),type:quiz.type,score,total:quiz.questions.length});
 if(quiz.section){const s=currentProfile.sectionStats[quiz.section]||{answered:0,correct:0,attempts:0,best:0};s.attempts++;s.best=Math.max(s.best||0,score);currentProfile.sectionStats[quiz.section]=s}
 save();renderAll();
 if(DATA.sections.filter(s=>sectionInfo(s).passed).length===DATA.sections.length)maybeCelebrateMilestone('All 11 section quizzes passed');
 area.innerHTML=`<div class="card"><h2>${passed?'Great work!':'Keep practicing'}</h2><div class="metric"><b>${score}%</b><span>${quiz.correct} of ${quiz.questions.length} correct</span></div><p>${passed
 ?(quiz.type.includes('Mastery')?'You demonstrated mastery of this section.':'You passed the section quiz.')
 :(quiz.type.includes('Mastery')?'Mastery requires 80%. Review weak topics before another attempt.':'A passing score is 80%. Review missed questions and try a new 15-question set.')}</p><button id="doneQuiz">Return to dashboard</button></div>`;
 document.querySelector('#doneQuiz').onclick=()=>{area.hidden=true;document.querySelector('#testSetup').hidden=false;quiz=null;switchTab('dashboard')}
}


function startSectionMasteryExam(section){
 const config=DATA.masteryModules?.[section];if(!config)return startSection(section);
 const pool=DATA.questions.filter(q=>q.section===section),buckets={1:[],2:[],3:[],4:[]},selected=[];
 pool.forEach(q=>(buckets[q.difficulty||3]||buckets[3]).push(q));
 Object.entries(config.requiredDifficultyMix||{}).forEach(([level,count])=>selected.push(...sampleWithoutReplacement(buckets[level]||[],count)));
 const target=config.masteryExamCount||25;
 if(selected.length<target)selected.push(...sampleWithoutReplacement(pool.filter(q=>!selected.some(x=>x.id===q.id)),target-selected.length));
 beginQuiz(shuffled(selected).slice(0,target),`${section} — 25-Question Mastery Exam`,section);
}


// ===== VERSION 7.0 PERMIT READINESS =====
function sectionMasteryScore(section){
 const i=sectionInfo(section),a=i.answered?pct(i.correct,i.answered):0,c=Math.min(100,Math.round((i.answered||0)/20*100));
 return Math.round((i.best||0)*.5+a*.35+c*.15);
}
function latestCapstone(){return (currentProfile.capstoneHistory||[]).slice().sort((a,b)=>b.date-a.date)[0]||null}
function certificationStatus(){
 const req=coachRequirements(),cap=latestCapstone(),completed=DATA.sections.filter(s=>sectionInfo(s).passed).length;
 const scores=cap?Object.values(cap.sectionResults||{}).filter(r=>r.total>0).map(r=>Math.round(r.correct/r.total*100)):[0];
 const floor=Math.min(...scores);
 return {req,cap,completed,floor,certified:Boolean(cap&&cap.score>=85&&floor>=70&&req.lessons.complete&&completed===DATA.sections.length&&req.exams.complete&&req.answered.complete)};
}
function buildCapstoneQuestions(total=50){
 const out=[],used=new Set();
 DATA.sections.forEach(s=>sampleWithoutReplacement(DATA.questions.filter(q=>q.section===s),3).forEach(q=>{out.push(q);used.add(q.id)}));
 const tickets=[];DATA.sections.forEach(s=>{for(let i=0;i<Math.max(2,Math.round((110-sectionMasteryScore(s))/8));i++)tickets.push(s)});
 while(out.length<total){
  const s=tickets[Math.floor(Math.random()*tickets.length)];
  let pool=DATA.questions.filter(q=>q.section===s&&!used.has(q.id));
  if(!pool.length)pool=DATA.questions.filter(q=>!used.has(q.id));
  if(!pool.length)break;
  const q=pool[Math.floor(Math.random()*pool.length)];out.push(q);used.add(q.id);
 }
 return shuffled(out).slice(0,total);
}
function startCapstoneExam(){
 const st=certificationStatus();
 if(!st.req.lessons.complete||st.completed<DATA.sections.length){alert(`Complete all lessons and pass all 11 section quizzes first.\n\nLessons: ${st.req.lessons.value}/${st.req.lessons.target}\nSections: ${st.completed}/11`);return}
 const questions=buildCapstoneQuestions();
 examSession={mode:'capstone',isFinal:true,questions,index:0,answers:[],started:Date.now(),secondsRemaining:45*60,
  displayQuestions:questions.map(q=>{const m=q.choices.map((text,i)=>({text,isCorrect:i===q.answer}));for(let i=m.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[m[i],m[j]]=[m[j],m[i]]}return {...q,choices:m.map(x=>x.text),answer:m.findIndex(x=>x.isCorrect)}})};
 document.querySelector('#testSetup').hidden=true;document.querySelector('#quizArea').hidden=false;document.body.classList.add('exam-active');switchTab('test');
 clearInterval(examTimerHandle);examTimerHandle=setInterval(()=>{if(!examSession)return;examSession.secondsRemaining--;updateExamTimer();if(examSession.secondsRemaining<=0)submitExam(true)},1000);renderExamQuestion();
}
function renderReadinessCenter(){
 if(!currentProfile)return;const el=document.querySelector('#readinessSummary');if(!el)return;
 const st=certificationStatus(),cap=st.cap,avg=Math.round(DATA.sections.reduce((a,s)=>a+sectionMasteryScore(s),0)/DATA.sections.length);
 const pc=(currentProfile.examHistory||[]).filter(x=>x.mode==='permit').length;
 el.innerHTML=[[readiness()+'%','Permit readiness'],[st.completed+'/11','Sections passed'],[avg+'%','Average mastery'],[pc,'Practice exams'],[cap?cap.score+'%':'—','Latest final']].map(x=>`<div class="readiness-stat"><b>${x[0]}</b><span>${x[1]}</span></div>`).join('');
 document.querySelector('#capstoneStatus').innerHTML=st.certified?`<b>Permit Ready achieved</b><br><span>Final ${cap.score}% • section floor ${st.floor}%</span>`:`<b>${st.completed}/11 sections passed</b><br><span>${cap?`Latest final ${cap.score}% • section floor ${st.floor}%`:'Final not completed'}</span>`;
 document.querySelector('#courseReview').innerHTML=DATA.sections.map(s=>{const m=sectionMasteryScore(s),i=sectionInfo(s);return `<div class="course-review-row ${m>=80?'mastered':'needs-review'}"><div class="course-review-head"><b>${s}</b><span>${m}%</span></div><div class="bar"><i style="width:${m}%"></i></div><small>Quiz best ${i.best||0}% • ${i.answered||0} questions answered</small></div>`}).sort((a,b)=>a.includes('needs-review')?-1:1).join('');
 document.querySelector('#certificateStatus').innerHTML=st.certified?`<div class="permit-ready-banner"><h2>PERMIT READY</h2><p>${currentProfile.name} met the family certification standard.</p><p>Final: <b>${cap.score}%</b></p></div>`:`<div class="not-ready-banner"><b>Certificate locked</b><p>Earn 85% on the final with no section below 70% after completing course requirements.</p></div>`;
 document.querySelector('#printCertificateBtn').disabled=!st.certified;
}
function recommendedSection(){return DATA.sections.map(s=>({s,m:sectionMasteryScore(s)})).sort((a,b)=>a.m-b.m)[0]?.s}
function printRoadReadyCertificate(){
 const st=certificationStatus();if(!st.certified)return;document.querySelector('#printableCertificate')?.remove();
 const n=document.createElement('div');n.id='printableCertificate';n.className='certificate-sheet';
 n.innerHTML=`<div class="certificate-preview"><div class="eyebrow">ROADREADY ACADEMY</div><h1>Certificate of Completion</h1><p>This certifies that</p><div class="certificate-name">${currentProfile.name}</div><p>completed the Tennessee Driver Education family study curriculum and demonstrated comprehensive permit readiness.</p><h2>Final Exam Score: ${st.cap.score}%</h2><p>All 11 knowledge sections completed</p><div class="certificate-seal">PERMIT<br>READY</div><p>Completed ${new Date(currentProfile.certifiedAt||st.cap.date).toLocaleDateString()}</p><small>Family study certificate — not an official Tennessee credential.</small></div>`;
 document.body.appendChild(n);window.print();
}
document.querySelector('#capstoneExamBtn').onclick=startCapstoneExam;
document.querySelector('#smartCourseReviewBtn').onclick=()=>{const s=recommendedSection();if(s){startSection(s);switchTab('test')}};
document.querySelector('#printCertificateBtn').onclick=printRoadReadyCertificate;
